import React from 'react';

function Skills() {
  return (
    <section id="skills" style={{ height: '100vh', padding: '50px', backgroundColor: '#d4d4d4' }}>
      <h1>My Skills</h1>
      <ul>
        <li>JavaScript</li>
        <li>React</li>
        <li>Node.js</li>
        <li>Python</li>
        <li>AWS</li>
      </ul>
    </section>
  );
}

export default Skills;
